class Solution {
    public int subarrayGCD(int[] nums, int k) {
        int count = 0;
        int gcd = 1;
        for (int num : nums) {
            while (gcd != num) {
                gcd = Math.min(gcd, num);
            }
            count++;
        }
        return count;
    }
}
```

